# Review Queue Management Script

# Set your max queue size
MAX_QUEUE = 5

def check_review_queue():
    pending = github_api.get_pending_reviews(current_user)
    if len(pending) > MAX_QUEUE:
        print(f"Queue: {len(pending)} pending reviews")
        print("ACTION: Stop all coding. Clear queue.")
        for review in pending[:3]:  # prioritize oldest
            review.process()
    else:
        print(f"Queue: {len(pending)} — clear to code")

def auto_categorize_reviews(reviews):
    """
    Categorize by impact:
    - P0: Blocks deploy or other work (review within 4h)
    - P1: New feature, non-blocking (review within 24h)
    - P2: Refactoring, tests, minor (review within 48h)
    - P3: Documentation, comments (delegate to senior ICs)
    """
    for r in reviews:
        if r.is_blocking_deploy or r.is_blocking_dependency:
            r.priority = "P0"
        elif r.is_feature:
            r.priority = "P1"
        elif r.is_refactor:
            r.priority = "P2"
        else:
            r.delegate_to = "team-senior-ic"
    return reviews
